#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int x, dp[n + 1];
        for (int i = 1; i <= n; i++) {
            dp[i] = -1;
        }
        for (int i = 0; i < m; i++) {
            scanf("%d", &x);
            if (dp[x] == -1) {
                dp[x] = (x % 2 == 0) ? 2 : 1;
            }
            printf("%d ", dp[x]);
        }
        printf("\n");
    }
    return 0;
}

