code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] dp = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                dp[i] = -1;
            }
            for (int i = 0; i < m; i++) {
                int x = sc.nextInt();
                if (dp[x] == -1) {
                    dp[x] = (x % 2 == 0) ? 2 : 1;
                }
                System.out.print(dp[x] + " ");
            }
            System.out.println();
        }
    }
}

code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [n, m] = readline().split(' ').map(Number);
    const dp = new Array(n + 1).fill(-1);
    const x = readline().split(' ').map(Number);
    for (let j = 0; j < m; j++) {
        if (dp[x[j]] == -1) {
            dp[x[j]] = (x[j] % 2 == 0) ? 2 : 1;
        }
        process.stdout.write(dp[x[j]] + ' ');
    }
    console.log();
}
